try {
  const [source, modified] = await rpc.enableTimeline(true)
  if (!await Dialog.start(source, modified))
    return
  await rpc.enableTimeline(false)
}
catch {
  devtoolsUiShowNotification({
    message: 'Failed to enable timeline automatically. Check the terminal for more details.',
    icon: 'i-carbon-warning',
    classes: 'text-red',
  })
}

for (const page of pages) {
  if (page.rules) {
    if (Object.keys(page.rules).length) {
      const glob = pathToNitroGlob(prefix + page.path)
      if (glob) {
        paths[glob] = page.rules
      }
    }
    // remove rules to prevent exposing in build
    delete page.rules
  }
  if (page.children?.length) {
    globRouteRulesFromPages(page.children, paths, prefix + page.path + '/')
  }
}

nuxt.hook('nitro:init', async (nitro) => {
  const t = new Telemetry(nuxt, nitro, toptions as typeof toptions & { consent: number })
  t.createEvent('project')
  // Only send the session in development
  if (nuxt.options.dev) {
    t.createEvent('session')
    t.createEvent('files')
  }
  t.createEvent('command')
  t.createEvent('module')
  await nuxt.callHook('telemetry:setup', t)
  t.sendEvents(toptions.debug)
})

const isRender = computed(() => {
  if (!filterState.search) {
    return true
  }
  else {
    const filteredCurrentItem = filterState.filtered.items.get(id)
    // If the filtered items is undefined means not in the all times map yet
    // Do the first render to add into the map
    if (filteredCurrentItem === undefined) {
      return true
    }

    // Check with filter
    return filteredCurrentItem > 0
  }
})

if (!nuxt.options.dev) {
  // DevOnly component tree-shaking - build time only
  addBuildPlugin(DevOnlyPlugin())

  // Extract async data handlers into separate chunks for better performance
  if (nuxt.options.experimental.extractAsyncDataHandlers) {
    addBuildPlugin(ExtractAsyncDataHandlersPlugin({
      sourcemap: !!nuxt.options.sourcemap.client,
      rootDir: nuxt.options.rootDir,
    }), { server: false })
  }
}

if (nuxtRobotsConfig) {
  const { header } = nuxtRobotsConfig
  const robotConfig = getPathRobotConfig(e, { skipSiteIndexable: Boolean(getQuery(e)?.mockProductionEnv) })
  if (header) {
    setHeader(e, 'X-Robots-Tag', robotConfig.rule)
  }
  e.context.robots = robotConfig

  // also compute production config for devtools
  if (import.meta.dev) {
    const productionRobotConfig = getPathRobotConfig(e, { skipSiteIndexable: true })
    setHeader(e, 'X-Robots-Production', productionRobotConfig.rule)
    e.context.robotsProduction = productionRobotConfig
  }
}

app.get('/checkout', async (_request, reply) => {
  const error = createError({
    message: 'Payment failed',
    status: 402,
    why: 'Card declined by issuer',
    fix: 'Try a different card or payment method',
    link: 'https://docs.example.com/payments/declined',
  })
  const parsed = parseError(error)
  reply.status(parsed.status).send({
    message: parsed.message,
    why: parsed.why,
    fix: parsed.fix,
    link: parsed.link,
  })
})

try {
  const stats = statSync(resolved)
  const currentMtime = stats.mtimeMs
  const lastMtime = this.mtimes.get(resolved)

  this.mtimes.set(resolved, currentMtime)

  // emit change for new file or mtime has changed
  return lastMtime === undefined || currentMtime !== lastMtime
}
catch {
  // remove from cache if it has been deleted or is inaccessible
  this.mtimes.delete(resolved)
  return true
}

if (options.colorMode || hasNuxtModule('@nuxtjs/color-mode')) {
  addComponentsDir({
    path: resolve('./runtime/components/color-mode'),
    pathPrefix: false,
    prefix: options.prefix
  })
} else {
  // Stub `useColorMode` composable used in `DashboardSearch` and `ContentSearch` components
  addImportsDir(resolve('./runtime/composables/color-mode'))
}

for (const article of articles) {
  if (article.draft) {
    continue
  }
  feed.addItem({
    link: joinURL(baseUrl, article.path),
    image: joinURL(baseUrl, article.image),
    title: article.title,
    date: new Date(article.date),
    description: article.description,
    category: [{
      name: article.category
    }]
    // author: article.authors, INF0: Cannot work without an email field in the author object https://github.com/jpmonette/feed/issues/141
  })
}

for (const resource of Object.values(styles)) {
  // Do not add links to resources that are inlined (vite v5+)
  if (import.meta.dev && 'inline' in getURLQuery(resource.file)) {
    continue
  }
  // Add CSS links in <head> for CSS files
  // - in production
  // - in dev mode when not rendering an island
  link.push({ rel: 'stylesheet', href: renderer.rendererContext.buildAssetsURL(resource.file), crossorigin: '' })
}

if (!NO_SCRIPTS) {
  ssrContext.head.push({
    script: Object.values(scripts).map(resource => (<Script> {
      type: resource.module ? 'module' : null,
      src: renderer.rendererContext.buildAssetsURL(resource.file),
      defer: resource.module ? null : true,
      // if we are rendering script tag payloads that import an async payload
      // we need to ensure this resolves before executing the Nuxt entry
      tagPosition: 'head',
      crossorigin: '',
    })),
  })
}

const heatmapLayer = useGoogleMapsResource<HeatmapLayer>({
  async create({ mapsApi, map }) {
    await mapsApi.importLibrary('visualization')
    const Layer = mapsApi.visualization.HeatmapLayer as unknown as new (opts: HeatmapLayerOptions) => HeatmapLayer
    return new Layer({
      map,
      ...props.options,
    })
  },
  cleanup(layer) {
    layer.setMap(null)
  },
})

nuxt.hook('modules:done', async () => {
  // generate database schema
  await generateDatabaseSchema(nuxt, hub as ResolvedHubConfig)
  // Call hub:db:migrations:dirs hook
  await nuxt.callHook('hub:db:migrations:dirs', migrationsDirs)
  // Copy all migrations files to the hub.dir directory
  await copyDatabaseMigrationsToHubDir(hub as ResolvedHubConfig)
  // Call hub:db:queries:paths hook
  await nuxt.callHook('hub:db:queries:paths', queriesPaths, dialect)
  await copyDatabaseQueriesToHubDir(hub as ResolvedHubConfig)
})

for (const locale of routeOptions.locales) {
  // use custom path if found
  const unprefixed = routeOptions.paths?.[locale] ?? route.path

  const prefixed = join('/', locale, unprefixed)
  const usePrefix = options.shouldPrefix(unprefixed, locale, options)

  const data = { route, prefixed, unprefixed, locale, usePrefix, ctx, options }
  for (const localizer of ctx.localizers) {
    if (!localizer.enabled(data)) { continue }
    resultRoutes.push(...localizer.localizer(data))
  }
}

for (const { prefix, overlapWord } of OGIMAGE_PREFIXES) {
  if (!stripped.startsWith(prefix))
    continue
  const withoutPrefix = stripped.slice(prefix.length)
  if (withoutPrefix) {
    names.push(withoutPrefix)
    // Account for Nuxt deduplication: if the filename started with the overlap word,
    // Nuxt would have merged it with the prefix, so re-prepend it as an alternative.
    if (withoutPrefix !== overlapWord)
      names.push(overlapWord + withoutPrefix)
  }
  else {
    names.push(overlapWord)
  }
  break
}

try {
  return asCollection(collection) as Collection<T>
}
catch (e) {
  console.warn(
    `[sitemap] Failed to apply sitemap schema to collection. This is likely a Zod version mismatch.`,
    `Pass your Zod instance explicitly: \`defineSitemapSchema({ z })\`. See https://nuxtseo.com/sitemap/guides/content`,
    `Error: ${(e as Error).message}`,
  )
  return collection
}

export const files = <EventFactory<FilesEvent>> async function (context) {
  const { options } = context.nuxt

  const nuxtIgnore = fs.existsSync(resolve(options.rootDir, '.nuxtignore'))
  const nuxtRc = fs.existsSync(resolve(options.rootDir, '.nuxtrc'))
  const appConfig = fs.existsSync(await resolvePath('~/app.config'))

  return {
    name: 'files',
    nuxtIgnore,
    nuxtRc,
    appConfig,
  }
}

const { data: page } = await useAsyncData('page-' + slug.value, async () => {
  const collection = ('content_' + locale.value) as keyof Collections
  const content = await queryCollection(collection).path(slug.value).first()

  // Possibly fallback to default locale if content is missing in non-default locale

  return content
}, {
  watch: [locale],
})

for (const dir of nuxt.options.modulesDir) {
  // we only need to exclude node_modules directories if they are
  // being included automatically by being inside the source directory
  if (!sourceDirs.some(srcDir => dir.startsWith(srcDir))) {
    exclude.add(relativeWithDot(nuxt.options.buildDir, dir))
  }
  nodeExclude.add(relativeWithDot(nuxt.options.buildDir, dir))
  legacyExclude.add(relativeWithDot(nuxt.options.buildDir, dir))
}

for (const version in pkgData.versions) {
  // Skip pre-release versions
  if (version.includes('-')) continue

  const match = version.match(/^(\d+)\./)
  if (!match || !match[1]) continue

  const major = Number.parseInt(match[1], 10)
  const current = majorVersionMap.get(major)

  // Keep the highest version for each major
  if (!current || semver.compare(version, current) > 0) {
    majorVersionMap.set(major, version)
  }
}

for (const filePath of componentFiles) {
  const vueSource = readFileSync(filePath, 'utf-8')
  const scriptSetup = extractScriptSetup(vueSource)
  if (!scriptSetup)
    continue

  const fileName = filePath.split('/').pop()!
  const meta = extractComponentMeta(scriptSetup, fileName.replace('.vue', '.ts'))
  if (meta) {
    componentMetas[fileName.replace('.vue', '')] = meta
  }
}

for (const locale of locales) {
  if (!locale.language) {
    console.warn('Locale `language` ISO code is required to generate alternate link')
    continue
  }

  const [language, region] = locale.language.split('-')
  if (language && region && (locale.isCatchallLocale || !localeMap.has(language))) {
    localeMap.set(language, locale)
  }

  localeMap.set(locale.language, locale)
}

for (const version of majorVersions) {
  await sleep(FETCH_DELAY)
  const moduleJson = await fetchModuleJson(mod.npm, version)
  if (moduleJson) {
    // Keep the latest module.json for other metadata
    if (!latestModuleJson) {
      latestModuleJson = moduleJson
    }

    if (moduleJson.compatibility?.nuxt) {
      nuxtCompatibilities.push(moduleJson.compatibility.nuxt)
    }
  }
}

return {
  getImage: (src, { modifiers, baseURL = prismicCDN }, ctx) => {
    // Some images served by Prismic are from unsplash, so we use the unsplash provider for those
    if (src.startsWith(unsplashCDN)) {
      return getUnsplashImage(src, { modifiers }, ctx)
    }

    const operations = operationsGenerator(modifiers)
    // withQuery requires query parameters as an object, so I parse the modifiers into an object with getQuery
    return {
      url: withQuery(withBase(src, baseURL), getQuery('?' + operations)),
    }
  },

}

for (const path of paths) {
  if (path.startsWith(base)) {
    resolved.push(path.split('/index.ts')[0]!)
    continue
  }
  const resolvedPath = await resolver.resolvePath(path)
  const dir = parseNodeModulePath(resolvedPath).dir
  if (dir) {
    resolved.push(dir)
    continue
  }
  const index = resolvedPath.lastIndexOf(path)
  resolved.push(index === -1 ? dirname(resolvedPath) : resolvedPath.slice(0, index + path.length))
}

const chartDescription = computed(() => {
  switch (chartType.value) {
    case 'line':
      return 'Track selected pages satisfaction over time'
    case 'compare':
      return 'Compare feedback distribution across pages'
    case 'overall':
      return 'Global documentation satisfaction evolution'
    default:
      return 'Track selected pages satisfaction over time'
  }
})

if (import.meta.server && nuxtApp.ssrContext) {
  nuxtApp.payload.path = nuxtApp.ssrContext.url

  // Expose nuxt to the renderContext
  nuxtApp.ssrContext.nuxt = nuxtApp
  nuxtApp.ssrContext.payload = nuxtApp.payload

  // Expose client runtime-config to the payload
  nuxtApp.ssrContext.config = {
    public: nuxtApp.ssrContext.runtimeConfig.public,
    app: nuxtApp.ssrContext.runtimeConfig.app,
  }
}

const middleware: RouteMiddleware = defineNuxtRouteMiddleware((to) => {
  if (import.meta.server || import.meta.test) { return }
  const rules = getRouteRules({ path: to.path })
  if (rules.redirect) {
    const path = rules.redirect.includes('#') ? rules.redirect : (rules.redirect + to.hash)
    if (hasProtocol(path, { acceptRelative: true })) {
      window.location.href = path
      return false
    }
    return path
  }
})

Object.entries(standardHeaders).forEach(([headerName, headerValue])  => {
  const optionKey = getKeyFromName(headerName)
  if (optionKey) {
    if (typeof headerValue === 'string') {
      // Normally, standard radix headers should be supplied as string
      const objectValue: any = headerObjectFromString(optionKey, headerValue)
      standardHeadersAsObject[optionKey] = objectValue
    } else {
      // Here we ensure backwards compatibility
      // Because in the pre-rc1 syntax, standard headers could also be supplied in object format
      standardHeadersAsObject[optionKey] = headerValue
      //standardHeaders[headerName] = headerStringFromObject(optionKey, headerValue)
    }
  }
})

if (!match) {
  throw createEvlogError({
    message: `[evlog/nuxthub] Invalid retention format: "${retention}"`,
    why: 'The retention value must be a number followed by a unit: d (days), h (hours), or m (minutes)',
    fix: `Change retention to a valid format, e.g., "30d", "24h", or "60m"`,
    link: 'https://evlog.dev/nuxthub/retention',
  })
}

import { eventHandler } from 'h3'
import { getUserSession, sessionHooks } from '../utils/session'

export default eventHandler(async (event) => {
  const session = await getUserSession(event)

  // If session is not empty, call fetch hook
  if (Object.keys(session).length > 0) {
    await sessionHooks.callHookParallel('fetch', session, event)
  }

  const { secure, ...data } = session

  return data
})
